import { QrCode as QrCodePrimitive, useQrCode, useQrCodeContext } from '@ark-ui/react/qr-code';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './QrCode.module.css';

const QrCodeRoot = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Root>,
  ComponentProps<typeof QrCodePrimitive.Root>
>(function QrCodeRoot({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Root
      ref={ref}
      data-slot="qr-code-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeRootProvider = forwardRef<
  ComponentRef<typeof QrCodePrimitive.RootProvider>,
  ComponentProps<typeof QrCodePrimitive.RootProvider>
>(function QrCodeRootProvider({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.RootProvider
      ref={ref}
      data-slot="qr-code-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeFrame = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Frame>,
  ComponentProps<typeof QrCodePrimitive.Frame>
>(function QrCodeFrame({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Frame
      ref={ref}
      data-slot="qr-code-frame"
      className={clsx(styles.frame, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodePattern = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Pattern>,
  ComponentProps<typeof QrCodePrimitive.Pattern>
>(function QrCodePattern({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Pattern
      ref={ref}
      data-slot="qr-code-pattern"
      className={clsx(styles.pattern, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeOverlay = forwardRef<
  ComponentRef<typeof QrCodePrimitive.Overlay>,
  ComponentProps<typeof QrCodePrimitive.Overlay>
>(function QrCodeOverlay({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.Overlay
      ref={ref}
      data-slot="qr-code-overlay"
      className={clsx(styles.overlay, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCodeDownloadTrigger = forwardRef<
  ComponentRef<typeof QrCodePrimitive.DownloadTrigger>,
  ComponentProps<typeof QrCodePrimitive.DownloadTrigger>
>(function QrCodeDownloadTrigger({ className, ...props }, ref) {
  return (
    <QrCodePrimitive.DownloadTrigger
      ref={ref}
      data-slot="qr-code-download-trigger"
      className={clsx(styles.downloadTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const QrCode = Object.assign(QrCodeRoot, {
  Root: QrCodeRoot,
  RootProvider: QrCodeRootProvider,
  Context: QrCodePrimitive.Context,
  Frame: QrCodeFrame,
  Pattern: QrCodePattern,
  Overlay: QrCodeOverlay,
  DownloadTrigger: QrCodeDownloadTrigger,
});

export { QrCode, useQrCode, useQrCodeContext };

@layer moduix.components {
  .root {
    position: relative;
    box-sizing: border-box;
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: var(--moduix-qr-code-gap, var(--moduix-spacing-3));
    width: fit-content;
    max-width: var(--moduix-qr-code-max-width, 100%);
    color: var(--moduix-qr-code-color, var(--moduix-color-foreground));
  }

  .frame {
    box-sizing: border-box;
    display: block;
    width: min(var(--moduix-qr-code-size, 8rem), 100%);
    aspect-ratio: 1;
    height: auto;
    color: inherit;
    fill: var(--moduix-qr-code-fill, currentColor);
  }

  .pattern {
    fill: inherit;
  }

  .overlay {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--moduix-qr-code-overlay-size, var(--moduix-size-lg));
    height: var(--moduix-qr-code-overlay-size, var(--moduix-size-lg));
    padding: var(--moduix-qr-code-overlay-padding, var(--moduix-spacing-1));
    border-radius: var(--moduix-qr-code-overlay-radius, var(--moduix-radius-sm));
    background-color: var(--moduix-qr-code-overlay-bg, var(--moduix-color-background));
    color: var(--moduix-qr-code-overlay-color, var(--moduix-color-foreground));
  }

  .overlay :where(img, svg) {
    width: 100%;
    height: 100%;
    object-fit: contain;
  }

  .downloadTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(
      --moduix-qr-code-download-trigger-gap,
      var(--moduix-button-content-gap, var(--moduix-spacing-2))
    );
    min-height: var(
      --moduix-qr-code-download-trigger-height,
      var(--moduix-button-size-md, var(--moduix-size-md))
    );
    padding-inline: var(
      --moduix-qr-code-download-trigger-padding-x,
      var(--moduix-button-padding-x-md, var(--moduix-spacing-4))
    );
    border: var(
        --moduix-qr-code-download-trigger-border-width,
        var(--moduix-button-border-width, var(--moduix-border-width-sm))
      )
      solid
      var(
        --moduix-qr-code-download-trigger-border-color,
        var(--moduix-button-outline-border-color, var(--moduix-color-border))
      );
    border-radius: var(
      --moduix-qr-code-download-trigger-radius,
      var(--moduix-button-radius, var(--moduix-radius-md))
    );
    background-color: var(
      --moduix-qr-code-download-trigger-bg,
      var(--moduix-button-outline-bg, var(--moduix-color-background))
    );
    color: var(
      --moduix-qr-code-download-trigger-color,
      var(--moduix-button-outline-color, var(--moduix-color-foreground))
    );
    appearance: none;
    font: inherit;
    font-size: var(
      --moduix-qr-code-download-trigger-font-size,
      var(--moduix-button-font-size, var(--moduix-text-sm))
    );
    font-weight: var(
      --moduix-qr-code-download-trigger-font-weight,
      var(--moduix-button-font-weight, var(--moduix-weight-medium))
    );
    line-height: var(
      --moduix-qr-code-download-trigger-line-height,
      var(--moduix-button-line-height, var(--moduix-line-height-text-sm))
    );
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      border-color
        var(
          --moduix-qr-code-transition,
          var(--moduix-button-transition, var(--moduix-transition-default))
        ),
      background-color
        var(
          --moduix-qr-code-transition,
          var(--moduix-button-transition, var(--moduix-transition-default))
        ),
      color
        var(
          --moduix-qr-code-transition,
          var(--moduix-button-transition, var(--moduix-transition-default))
        ),
      opacity
        var(
          --moduix-qr-code-transition,
          var(--moduix-button-transition, var(--moduix-transition-default))
        ),
      box-shadow
        var(
          --moduix-qr-code-transition,
          var(--moduix-button-transition, var(--moduix-transition-default))
        );
  }

  .downloadTrigger :where(svg) {
    width: var(
      --moduix-qr-code-download-trigger-icon-size,
      var(--moduix-button-icon-size, var(--moduix-spacing-4))
    );
    height: var(
      --moduix-qr-code-download-trigger-icon-size,
      var(--moduix-button-icon-size, var(--moduix-spacing-4))
    );
    flex-shrink: 0;
  }

  @media (hover: hover) {
    .downloadTrigger:hover:not(:disabled, [data-disabled]) {
      background-color: var(
        --moduix-qr-code-download-trigger-bg-hover,
        var(--moduix-button-outline-bg-hover, var(--moduix-color-accent))
      );
    }
  }

  .downloadTrigger:focus-visible {
    outline: var(
        --moduix-qr-code-download-trigger-focus-ring-width,
        var(
          --moduix-button-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
      )
      solid
      var(
        --moduix-qr-code-download-trigger-focus-ring-color,
        var(--moduix-button-focus-ring-color, var(--moduix-color-ring))
      );
    outline-offset: calc(
      var(
          --moduix-qr-code-download-trigger-focus-ring-offset,
          var(
            --moduix-qr-code-download-trigger-border-width,
            var(--moduix-button-border-width, var(--moduix-border-width-sm))
          )
        ) *
        -1
    );
  }

  .downloadTrigger:disabled,
  .downloadTrigger[data-disabled] {
    pointer-events: none;
    opacity: var(
      --moduix-qr-code-disabled-opacity,
      var(--moduix-button-disabled-opacity, var(--moduix-opacity-disabled))
    );
  }
}
